import React, { useState, useRef, useEffect } from 'react';
import { Search, Copy, Check, X } from 'lucide-react';
import { BRANCH_DATABASE, toBanglaDigits, toEnglishDigits } from '../constants';
import { BranchData } from '../types';

interface SearchSectionProps {
  onSearchComplete: () => void;
}

const SearchSection: React.FC<SearchSectionProps> = ({ onSearchComplete }) => {
  const [query, setQuery] = useState('');
  const [suggestions, setSuggestions] = useState<{ code: string; data: BranchData }[]>([]);
  const [result, setResult] = useState<{ code: string; data: BranchData } | null>(null);
  const [loading, setLoading] = useState(false);
  const [copiedField, setCopiedField] = useState<string | null>(null);
  const wrapperRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (wrapperRef.current && !wrapperRef.current.contains(event.target as Node)) {
        setSuggestions([]);
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, [wrapperRef]);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const val = e.target.value;
    setQuery(val);

    if (val.length < 2) {
      setSuggestions([]);
      return;
    }

    const searchTerm = toEnglishDigits(val.toLowerCase());
    const matches: { code: string; data: BranchData }[] = [];

    Object.keys(BRANCH_DATABASE).forEach((code) => {
      const data = BRANCH_DATABASE[code];
      const searchText = (code + data.branch + data.name + data.mobile).toLowerCase();
      if (searchText.includes(searchTerm)) {
        matches.push({ code, data });
      }
    });
    setSuggestions(matches.slice(0, 8));
  };

  const executeSearch = (searchCode?: string) => {
    const codeToSearch = searchCode || toEnglishDigits(query);
    setLoading(true);
    setSuggestions([]);

    setTimeout(() => {
      const data = BRANCH_DATABASE[codeToSearch];
      if (data) {
        setResult({ code: codeToSearch, data });
        onSearchComplete();
      } else {
        setResult(null);
        alert('কোনো তথ্য পাওয়া যায়নি');
      }
      setLoading(false);
    }, 400);
  };

  const copyToClipboard = (text: string, field: string) => {
    navigator.clipboard.writeText(text);
    setCopiedField(field);
    setTimeout(() => setCopiedField(null), 2000);
  };

  return (
    <div className="bg-white p-6 rounded-2xl shadow-lg border border-emerald-100 mb-6 transition-all duration-300 hover:shadow-xl">
      <div className="flex items-center gap-3 mb-6 border-b border-gray-100 pb-4">
        <span className="bg-emerald-600 text-white w-8 h-8 flex items-center justify-center rounded-full font-bold">১</span>
        <h2 className="text-xl font-bold text-gray-800">দ্রুত অনুসন্ধান (Single Search)</h2>
      </div>

      <div className="relative mb-6" ref={wrapperRef}>
        <div className="flex gap-2">
          <div className="relative flex-1">
            <input
              type="text"
              value={query}
              onChange={handleInputChange}
              onKeyDown={(e) => e.key === 'Enter' && executeSearch()}
              placeholder="কোড, শাখার নাম বা কর্মকর্তার নাম লিখুন..."
              className="w-full p-4 pl-12 border-2 border-gray-200 rounded-xl focus:border-emerald-500 focus:ring-0 outline-none transition-all text-lg"
            />
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" />
          </div>
          <button
            onClick={() => executeSearch()}
            disabled={loading}
            className="bg-emerald-600 hover:bg-emerald-700 text-white px-8 rounded-xl font-bold shadow-md shadow-emerald-200 transition-all active:scale-95 disabled:opacity-50"
          >
            {loading ? 'খুঁজছি...' : 'খুঁজুন'}
          </button>
        </div>

        {suggestions.length > 0 && (
          <div className="absolute top-full left-0 right-0 bg-white border border-gray-200 rounded-xl mt-2 shadow-2xl z-50 max-h-60 overflow-y-auto">
            {suggestions.map((item) => (
              <div
                key={item.code}
                onClick={() => {
                  setQuery(item.code);
                  executeSearch(item.code);
                }}
                className="p-3 hover:bg-emerald-50 cursor-pointer border-b border-gray-50 last:border-0 flex justify-between items-center"
              >
                <div>
                  <span className="font-bold text-emerald-700 mr-2">{toBanglaDigits(item.code)}</span>
                  <span className="text-gray-700">{item.data.branch}</span>
                </div>
                <span className="text-gray-400 text-sm">{item.data.name}</span>
              </div>
            ))}
          </div>
        )}
      </div>

      {result && (
        <div className="bg-gradient-to-br from-emerald-50 to-white border border-emerald-100 rounded-xl p-6 animate-in slide-in-from-top-4 duration-500">
          <div className="grid gap-4">
             {[
               { label: 'শাখার নাম', value: result.data.branch, key: 'branch' },
               { label: 'কর্মকর্তার নাম', value: result.data.name, key: 'name' },
               { label: 'মোবাইল', value: result.data.mobile, key: 'mobile' },
               { label: 'এক্সটেনশন', value: result.data.ext, key: 'ext' },
               { label: 'ইমেইল', value: result.data.email, key: 'email' },
             ].map((row) => (
               <div key={row.key} className="flex items-center justify-between border-b border-emerald-100 pb-2 last:border-0">
                 <span className="font-bold text-gray-600 w-1/3">{row.label}:</span>
                 <span className="text-emerald-800 font-medium flex-1 text-right mr-4">{row.value}</span>
                 <button 
                   onClick={() => copyToClipboard(row.value, row.key)}
                   className="p-2 hover:bg-emerald-200 rounded-lg text-emerald-600 transition-colors"
                   title="কপি করুন"
                 >
                   {copiedField === row.key ? <Check size={18} /> : <Copy size={18} />}
                 </button>
               </div>
             ))}
          </div>
        </div>
      )}
    </div>
  );
};

export default SearchSection;

import React, { useState } from 'react';
import { FileSpreadsheet, Printer, Save, Trash2, AlertCircle } from 'lucide-react';
import { BRANCH_DATABASE, toBanglaDigits, toEnglishDigits, formatCurrency } from '../constants';
import { BillItem } from '../types';

interface BillSectionProps {
  onTotalChange: (amount: number) => void;
}

const BillSection: React.FC<BillSectionProps> = ({ onTotalChange }) => {
  const [inputCodes, setInputCodes] = useState('');
  const [billItems, setBillItems] = useState<BillItem[]>([]);
  const [loading, setLoading] = useState(false);
  const [note, setNote] = useState('');
  const [notFoundCodes, setNotFoundCodes] = useState<string[]>([]);

  const handleGenerateList = () => {
    if (!inputCodes.trim()) return;

    setLoading(true);
    setNotFoundCodes([]);

    // Parse codes
    const codes = inputCodes.split(/[\s,]+/).map(c => toEnglishDigits(c.trim())).filter(c => c);

    setTimeout(() => {
      const newItems: BillItem[] = [];
      const missing: string[] = [];

      codes.forEach(code => {
        if (BRANCH_DATABASE[code]) {
          newItems.push({
            ...BRANCH_DATABASE[code],
            code: code,
            serial: '',
            amount: ''
          });
        } else {
          missing.push(toBanglaDigits(code));
        }
      });

      setBillItems(newItems);
      setNotFoundCodes(missing);
      setLoading(false);
      calculateTotal(newItems);
    }, 600);
  };

  const handleInputChange = (index: number, field: 'serial' | 'amount', value: string) => {
    const newItems = [...billItems];
    // Keep raw input, handle conversions on blur or rely on formatting for display
    if (field === 'amount') {
        // Strip non-numeric for calculation but allow typing
        newItems[index][field] = value; 
        calculateTotal(newItems);
    } else {
        newItems[index][field] = value;
    }
    setBillItems(newItems);
  };

  const calculateTotal = (items: BillItem[]) => {
    let total = 0;
    items.forEach(item => {
        const engVal = toEnglishDigits(item.amount.replace(/,/g, ''));
        const num = parseFloat(engVal);
        if (!isNaN(num)) total += num;
    });
    onTotalChange(total);
  };

  const getTotal = () => {
    let total = 0;
    billItems.forEach(item => {
        const engVal = toEnglishDigits(item.amount.replace(/,/g, ''));
        const num = parseFloat(engVal);
        if (!isNaN(num)) total += num;
    });
    return total;
  };

  const handlePrint = () => {
    const printWindow = window.open('', '_blank');
    if(!printWindow) return;

    const tableRows = billItems.map((item, idx) => `
        <tr>
            <td style="text-align:center">${toBanglaDigits(idx + 1)}</td>
            <td style="text-align:center">${toBanglaDigits(item.code)}</td>
            <td>${item.branch}</td>
            <td>${item.name}</td>
            <td style="text-align:center">${item.mobile}</td>
            <td style="text-align:center">${item.serial || '-'}</td>
            <td style="text-align:right; font-weight:bold">${item.amount ? toBanglaDigits(item.amount) : '০'}</td>
        </tr>
    `).join('');

    const htmlContent = `
        <!DOCTYPE html>
        <html lang="bn">
        <head>
            <meta charset="UTF-8">
            <title>সোনালী লাইফ - বিল তালিকা</title>
            <link href="https://fonts.googleapis.com/css2?family=Hind+Siliguri:wght@400;500;600&display=swap" rel="stylesheet">
            <style>
                body { font-family: 'Hind Siliguri', sans-serif; padding: 40px; color: #111; }
                .header { text-align: center; margin-bottom: 30px; border-bottom: 2px solid #047857; padding-bottom: 20px; }
                h1 { color: #047857; margin: 0; font-size: 28px; }
                table { width: 100%; border-collapse: collapse; margin-top: 20px; font-size: 14px; }
                th { background-color: #047857; color: white; padding: 10px; border: 1px solid #065f46; }
                td { border: 1px solid #ccc; padding: 8px; }
                .total-row { background-color: #f0fdf4; font-weight: bold; }
                .footer { margin-top: 50px; display: flex; justify-content: flex-end; }
                .signature { border-top: 1px solid #000; padding-top: 5px; width: 200px; text-align: center; }
            </style>
        </head>
        <body>
            <div class="header">
                <h1>সোনালী লাইফ ইন্স্যুরেন্স</h1>
                <p>পেমেন্ট তালিকা | তারিখ: ${new Date().toLocaleDateString('bn-BD')}</p>
            </div>
            <table>
                <thead>
                    <tr>
                        <th>ক্রমিক</th><th>কোড</th><th>শাখা</th><th>নাম</th><th>মোবাইল</th><th>সিরিয়াল</th><th>টাকা</th>
                    </tr>
                </thead>
                <tbody>
                    ${tableRows}
                    <tr class="total-row">
                        <td colspan="6" style="text-align:right">সর্বমোট:</td>
                        <td style="text-align:right">${toBanglaDigits(getTotal())}</td>
                    </tr>
                </tbody>
            </table>
            ${note ? `<div style="margin-top:20px; padding:15px; background:#f9f9f9; border:1px solid #eee;"><strong>নোট:</strong> ${note}</div>` : ''}
            <div class="footer">
                <div class="signature">কর্তৃপক্ষের স্বাক্ষর</div>
            </div>
            <script>window.print();</script>
        </body>
        </html>
    `;
    printWindow.document.write(htmlContent);
    printWindow.document.close();
  };

  const handleDownloadCSV = () => {
    // CSV Logic similar to original but type-safe
    let content = "\uFEFFক্রমিক,কোড,শাখা,নাম,মোবাইল,সিরিয়াল,টাকা\n";
    billItems.forEach((item, idx) => {
        content += `"${toBanglaDigits(idx+1)}","${toBanglaDigits(item.code)}","${item.branch}","${item.name}","${item.mobile}","${item.serial}","${toBanglaDigits(item.amount || 0)}"\n`;
    });
    content += `,,,,,,সর্বমোট: ${toBanglaDigits(getTotal())}\n`;

    const blob = new Blob([content], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `sonali_list_${Date.now()}.csv`;
    link.click();
  };

  return (
    <div className="space-y-6">
      <div className="bg-white p-6 rounded-2xl shadow-lg border border-emerald-100">
        <div className="flex items-center gap-3 mb-6 border-b border-gray-100 pb-4">
          <span className="bg-orange-500 text-white w-8 h-8 flex items-center justify-center rounded-full font-bold">২</span>
          <h2 className="text-xl font-bold text-gray-800">বিল / তালিকা তৈরি (Custom List)</h2>
        </div>

        <div className="mb-4">
          <label className="block text-gray-700 font-medium mb-2">কোডগুলো লিখুন (কমা দিয়ে আলাদা করুন)</label>
          <textarea
            value={inputCodes}
            onChange={(e) => setInputCodes(e.target.value)}
            placeholder="যেমন: ৩৪১, ২৮৫, ১৮৫, ২৮৪"
            className="w-full h-24 p-4 border-2 border-gray-200 rounded-xl focus:border-orange-500 focus:ring-0 outline-none transition-all resize-none"
          />
        </div>

        <div className="flex gap-3">
          <button
            onClick={handleGenerateList}
            disabled={loading}
            className="bg-orange-500 hover:bg-orange-600 text-white px-6 py-3 rounded-xl font-bold shadow-md shadow-orange-100 transition-all active:scale-95 disabled:opacity-50 flex-1"
          >
            {loading ? 'প্রসেসিং...' : 'লিস্ট তৈরি করুন'}
          </button>
          <button
            onClick={() => { setInputCodes(''); setBillItems([]); onTotalChange(0); }}
            className="bg-gray-100 hover:bg-gray-200 text-gray-600 px-6 py-3 rounded-xl font-bold transition-all"
          >
            মুছুন
          </button>
        </div>

        {notFoundCodes.length > 0 && (
            <div className="mt-4 p-3 bg-red-50 text-red-600 rounded-lg flex items-start gap-2 text-sm">
                <AlertCircle size={16} className="mt-1 flex-shrink-0" />
                <span>পাওয়া যায়নি: {notFoundCodes.join(', ')}</span>
            </div>
        )}
      </div>

      {billItems.length > 0 && (
        <div className="bg-white p-6 rounded-2xl shadow-lg border border-emerald-100 animate-in fade-in slide-in-from-bottom-4 duration-500">
          <div className="flex flex-col md:flex-row justify-between items-center mb-6 gap-4">
            <h3 className="text-xl font-bold text-gray-800">পেমেন্ট তালিকা</h3>
            <div className="flex gap-2">
                <button onClick={handleDownloadCSV} className="flex items-center gap-2 px-4 py-2 bg-green-600 text-white rounded-lg hover:bg-green-700 transition-colors shadow-sm">
                    <FileSpreadsheet size={18} /> Excel
                </button>
                <button onClick={handlePrint} className="flex items-center gap-2 px-4 py-2 bg-purple-600 text-white rounded-lg hover:bg-purple-700 transition-colors shadow-sm">
                    <Printer size={18} /> Print
                </button>
            </div>
          </div>

          <div className="overflow-x-auto rounded-lg border border-gray-200">
            <table className="w-full text-left">
              <thead className="bg-gray-50 text-gray-600 font-semibold uppercase text-sm">
                <tr>
                  <th className="p-4">#</th>
                  <th className="p-4">কোড</th>
                  <th className="p-4">শাখা</th>
                  <th className="p-4 w-32">সিরিয়াল</th>
                  <th className="p-4 w-40 text-right">টাকা</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-100">
                {billItems.map((item, idx) => (
                  <tr key={idx} className="hover:bg-gray-50 transition-colors">
                    <td className="p-4 text-gray-500">{toBanglaDigits(idx + 1)}</td>
                    <td className="p-4 font-bold text-emerald-700">{toBanglaDigits(item.code)}</td>
                    <td className="p-4">
                        <div className="font-medium text-gray-800">{item.branch}</div>
                        <div className="text-xs text-gray-500">{item.name}</div>
                    </td>
                    <td className="p-4">
                      <input
                        type="text"
                        value={toBanglaDigits(item.serial)}
                        onChange={(e) => handleInputChange(idx, 'serial', toEnglishDigits(e.target.value))}
                        placeholder="S/N"
                        className="w-full p-2 border border-gray-300 rounded text-center focus:border-emerald-500 outline-none bg-white"
                      />
                    </td>
                    <td className="p-4">
                      <input
                        type="text"
                        value={toBanglaDigits(item.amount)}
                        onChange={(e) => handleInputChange(idx, 'amount', toEnglishDigits(e.target.value))}
                        placeholder="0"
                        className="w-full p-2 border border-gray-300 rounded text-right font-bold text-gray-800 focus:border-emerald-500 outline-none bg-white"
                      />
                    </td>
                  </tr>
                ))}
              </tbody>
              <tfoot className="bg-gray-50 font-bold">
                <tr>
                    <td colSpan={4} className="p-4 text-right text-gray-600">সর্বমোট:</td>
                    <td className="p-4 text-right text-emerald-700 text-lg">{toBanglaDigits(getTotal())}</td>
                </tr>
              </tfoot>
            </table>
          </div>

          <div className="mt-6">
            <label className="block text-gray-700 font-medium mb-2">বিশেষ নোট (ঐচ্ছিক)</label>
            <textarea
                value={note}
                onChange={(e) => setNote(e.target.value)}
                placeholder="বিল সম্পর্কিত কোনো মন্তব্য..."
                className="w-full p-3 border border-gray-200 rounded-xl focus:border-emerald-500 outline-none"
            />
          </div>
        </div>
      )}
    </div>
  );
};

export default BillSection;

