export type TabType = 'search' | 'list' | 'settings';

import React, { useEffect } from 'react';
import { CheckCircle, AlertCircle, Info, X } from 'lucide-react';
import { ToastData } from '../types';

interface ToastProps {
  toasts: ToastData[];
  removeToast: (id: number) => void;
}

const Toast: React.FC<ToastProps> = ({ toasts, removeToast }) => {
  return (
    <div className="fixed bottom-4 right-4 z-[100] flex flex-col gap-2 pointer-events-none">
      {toasts.map((toast) => (
        <ToastItem key={toast.id} toast={toast} onRemove={() => removeToast(toast.id)} />
      ))}
    </div>
  );
};

const ToastItem: React.FC<{ toast: ToastData; onRemove: () => void }> = ({ toast, onRemove }) => {
  useEffect(() => {
    const timer = setTimeout(() => {
      onRemove();
    }, 3000);
    return () => clearTimeout(timer);
  }, [onRemove]);

  const styles = {
    success: 'bg-emerald-50 border-emerald-200 text-emerald-800',
    error: 'bg-red-50 border-red-200 text-red-800',
    info: 'bg-blue-50 border-blue-200 text-blue-800',
  };

  const icons = {
    success: <CheckCircle size={18} className="text-emerald-600" />,
    error: <AlertCircle size={18} className="text-red-600" />,
    info: <Info size={18} className="text-blue-600" />,
  };

  return (
    <div className={`pointer-events-auto flex items-center gap-3 px-4 py-3 rounded-xl border shadow-lg shadow-gray-200/50 min-w-[300px] animate-in slide-in-from-right-full duration-300 ${styles[toast.type]}`}>
      {icons[toast.type]}
      <p className="flex-1 font-medium text-sm">{toast.message}</p>
      <button onClick={onRemove} className="opacity-50 hover:opacity-100 transition-opacity">
        <X size={16} />
      </button>
    </div>
  );
};

export default Toast;

import React, { useState, useRef, useEffect } from 'react';
import { Search, Copy, Check, PlusCircle, Clock, RotateCcw } from 'lucide-react';
import { BRANCH_DATABASE, toBanglaDigits, toEnglishDigits } from '../constants';
import { BranchData } from '../types';

interface SearchSectionProps {
  onSearchComplete: () => void;
  onAddToBill: (code: string, data: BranchData) => void;
}

const SearchSection: React.FC<SearchSectionProps> = ({ onSearchComplete, onAddToBill }) => {
  const [query, setQuery] = useState('');
  const [suggestions, setSuggestions] = useState<{ code: string; data: BranchData }[]>([]);
  const [result, setResult] = useState<{ code: string; data: BranchData } | null>(null);
  const [loading, setLoading] = useState(false);
  const [copiedField, setCopiedField] = useState<string | null>(null);
  const [recentSearches, setRecentSearches] = useState<{ code: string; name: string }[]>([]);
  const wrapperRef = useRef<HTMLDivElement>(null);

  // Load recent searches
  useEffect(() => {
    const saved = localStorage.getItem('sonali_recent_searches');
    if (saved) {
      setRecentSearches(JSON.parse(saved));
    }
  }, []);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (wrapperRef.current && !wrapperRef.current.contains(event.target as Node)) {
        setSuggestions([]);
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, [wrapperRef]);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const val = e.target.value;
    setQuery(val);

    if (val.length < 2) {
      setSuggestions([]);
      return;
    }

    const searchTerm = toEnglishDigits(val.toLowerCase());
    const matches: { code: string; data: BranchData }[] = [];

    Object.keys(BRANCH_DATABASE).forEach((code) => {
      const data = BRANCH_DATABASE[code];
      const searchText = (code + data.branch + data.name + data.mobile).toLowerCase();
      if (searchText.includes(searchTerm)) {
        matches.push({ code, data });
      }
    });
    setSuggestions(matches.slice(0, 8));
  };

  const addToRecent = (code: string, name: string) => {
    const newRecent = [{ code, name }, ...recentSearches.filter(r => r.code !== code)].slice(0, 6);
    setRecentSearches(newRecent);
    localStorage.setItem('sonali_recent_searches', JSON.stringify(newRecent));
  };

  const executeSearch = (searchCode?: string) => {
    const codeToSearch = searchCode || toEnglishDigits(query);
    setLoading(true);
    setSuggestions([]);

    setTimeout(() => {
      const data = BRANCH_DATABASE[codeToSearch];
      if (data) {
        setResult({ code: codeToSearch, data });
        addToRecent(codeToSearch, data.branch);
        onSearchComplete();
      } else {
        setResult(null);
        // Using alert here as fallback, but ideally parent handles errors via toast if we passed error up
      }
      setLoading(false);
    }, 400);
  };

  const copyToClipboard = (text: string, field: string) => {
    navigator.clipboard.writeText(text);
    setCopiedField(field);
    setTimeout(() => setCopiedField(null), 2000);
  };

  return (
    <div className="bg-white p-6 rounded-2xl shadow-lg border border-emerald-100 mb-6 transition-all duration-300 hover:shadow-xl relative overflow-hidden">
      <div className="flex items-center gap-3 mb-6 border-b border-gray-100 pb-4">
        <span className="bg-emerald-600 text-white w-8 h-8 flex items-center justify-center rounded-full font-bold">১</span>
        <h2 className="text-xl font-bold text-gray-800">দ্রুত অনুসন্ধান (Single Search)</h2>
      </div>

      <div className="relative mb-6" ref={wrapperRef}>
        <div className="flex gap-2">
          <div className="relative flex-1">
            <input
              type="text"
              value={query}
              onChange={handleInputChange}
              onKeyDown={(e) => e.key === 'Enter' && executeSearch()}
              placeholder="কোড, শাখার নাম বা কর্মকর্তার নাম..."
              className="w-full p-4 pl-12 border-2 border-gray-200 rounded-xl focus:border-emerald-500 focus:ring-0 outline-none transition-all text-lg"
            />
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" />
          </div>
          <button
            onClick={() => executeSearch()}
            disabled={loading}
            className="bg-emerald-600 hover:bg-emerald-700 text-white px-8 rounded-xl font-bold shadow-md shadow-emerald-200 transition-all active:scale-95 disabled:opacity-50"
          >
            {loading ? '...' : 'খুঁজুন'}
          </button>
        </div>

        {suggestions.length > 0 && (
          <div className="absolute top-full left-0 right-0 bg-white border border-gray-200 rounded-xl mt-2 shadow-2xl z-50 max-h-60 overflow-y-auto">
            {suggestions.map((item) => (
              <div
                key={item.code}
                onClick={() => {
                  setQuery(item.code);
                  executeSearch(item.code);
                }}
                className="p-3 hover:bg-emerald-50 cursor-pointer border-b border-gray-50 last:border-0 flex justify-between items-center"
              >
                <div>
                  <span className="font-bold text-emerald-700 mr-2">{toBanglaDigits(item.code)}</span>
                  <span className="text-gray-700">{item.data.branch}</span>
                </div>
                <span className="text-gray-400 text-sm">{item.data.name}</span>
              </div>
            ))}
          </div>
        )}
      </div>

      {/* Recent Searches */}
      {!result && recentSearches.length > 0 && (
        <div className="mb-4 animate-in fade-in duration-500">
            <p className="text-xs text-gray-400 font-bold uppercase mb-2 flex items-center gap-1">
                <Clock size={12} /> সাম্প্রতিক অনুসন্ধান
            </p>
            <div className="flex flex-wrap gap-2">
                {recentSearches.map((item) => (
                    <button
                        key={item.code}
                        onClick={() => { setQuery(item.code); executeSearch(item.code); }}
                        className="text-xs bg-gray-100 hover:bg-emerald-100 hover:text-emerald-700 text-gray-600 px-3 py-1.5 rounded-full transition-colors border border-gray-200"
                    >
                        {toBanglaDigits(item.code)} - {item.name}
                    </button>
                ))}
            </div>
        </div>
      )}

      {result && (
        <div className="bg-gradient-to-br from-emerald-50 to-white border border-emerald-100 rounded-xl p-6 animate-in slide-in-from-top-4 duration-500 relative">
          <button 
             onClick={() => setResult(null)} 
             className="absolute top-4 right-4 text-gray-400 hover:text-red-500 transition-colors"
             title="বন্ধ করুন"
          >
             <RotateCcw size={18} />
          </button>

          <div className="grid gap-3">
             {[
               { label: 'শাখা', value: result.data.branch, key: 'branch' },
               { label: 'কর্মকর্তা', value: result.data.name, key: 'name' },
               { label: 'মোবাইল', value: result.data.mobile, key: 'mobile' },
               { label: 'এক্সটেনশন', value: result.data.ext, key: 'ext' },
               { label: 'ইমেইল', value: result.data.email, key: 'email' },
             ].map((row) => (
               <div key={row.key} className="flex items-center justify-between border-b border-emerald-100 pb-2 last:border-0">
                 <span className="text-sm font-bold text-gray-500 w-1/3">{row.label}:</span>
                 <span className="text-emerald-900 font-medium flex-1 text-right mr-3 truncate">{row.value}</span>
                 <button 
                   onClick={() => copyToClipboard(row.value, row.key)}
                   className="p-1.5 hover:bg-emerald-200 rounded-md text-emerald-600 transition-colors"
                   title="কপি করুন"
                 >
                   {copiedField === row.key ? <Check size={14} /> : <Copy size={14} />}
                 </button>
               </div>
             ))}
          </div>

          <div className="mt-6 pt-4 border-t border-emerald-100">
             <button
               onClick={() => onAddToBill(result.code, result.data)}
               className="w-full bg-emerald-800 hover:bg-emerald-900 text-white py-3 rounded-xl font-bold flex items-center justify-center gap-2 shadow-lg shadow-emerald-200 active:scale-95 transition-all"
             >
                <PlusCircle size={18} />
                লিস্টে যোগ করুন
             </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default SearchSection;

import React, { useState } from 'react';
import { FileSpreadsheet, Printer, Trash2, AlertCircle, Plus, Eraser } from 'lucide-react';
import { BRANCH_DATABASE, toBanglaDigits, toEnglishDigits } from '../constants';
import { BillItem } from '../types';

interface BillSectionProps {
  billItems: BillItem[];
  setBillItems: React.Dispatch<React.SetStateAction<BillItem[]>>;
  totalAmount: number;
}

const BillSection: React.FC<BillSectionProps> = ({ billItems, setBillItems, totalAmount }) => {
  const [inputCodes, setInputCodes] = useState('');
  const [loading, setLoading] = useState(false);
  const [note, setNote] = useState('');
  const [notFoundCodes, setNotFoundCodes] = useState<string[]>([]);

  const handleGenerateList = () => {
    if (!inputCodes.trim()) return;

    setLoading(true);
    setNotFoundCodes([]);

    // Parse codes
    const codes = inputCodes.split(/[\s,]+/).map(c => toEnglishDigits(c.trim())).filter(c => c);

    setTimeout(() => {
      const newItems: BillItem[] = [];
      const missing: string[] = [];

      codes.forEach(code => {
        if (BRANCH_DATABASE[code]) {
          newItems.push({
            ...BRANCH_DATABASE[code],
            code: code,
            serial: '',
            amount: ''
          });
        } else {
          missing.push(toBanglaDigits(code));
        }
      });

      setBillItems(prev => [...prev, ...newItems]);
      setNotFoundCodes(missing);
      setInputCodes(''); // Clear input after adding
      setLoading(false);
    }, 400);
  };

  const handleInputChange = (index: number, field: 'serial' | 'amount', value: string) => {
    const newItems = [...billItems];
    newItems[index][field] = value;
    setBillItems(newItems);
  };

  const removeItem = (index: number) => {
    const newItems = billItems.filter((_, i) => i !== index);
    setBillItems(newItems);
  };

  const handlePrint = () => {
    const printWindow = window.open('', '_blank');
    if(!printWindow) return;

    const tableRows = billItems.map((item, idx) => `
        <tr>
            <td style="text-align:center">${toBanglaDigits(idx + 1)}</td>
            <td style="text-align:center">${toBanglaDigits(item.code)}</td>
            <td>${item.branch}</td>
            <td>${item.name}</td>
            <td style="text-align:center">${item.mobile}</td>
            <td style="text-align:center">${item.serial || '-'}</td>
            <td style="text-align:right; font-weight:bold">${item.amount ? toBanglaDigits(item.amount) : '০'}</td>
        </tr>
    `).join('');

    const htmlContent = `
        <!DOCTYPE html>
        <html lang="bn">
        <head>
            <meta charset="UTF-8">
            <title>সোনালী লাইফ - বিল তালিকা</title>
            <link href="https://fonts.googleapis.com/css2?family=Hind+Siliguri:wght@400;500;600&display=swap" rel="stylesheet">
            <style>
                body { font-family: 'Hind Siliguri', sans-serif; padding: 40px; color: #111; }
                .header { text-align: center; margin-bottom: 30px; border-bottom: 2px solid #047857; padding-bottom: 20px; }
                h1 { color: #047857; margin: 0; font-size: 28px; }
                table { width: 100%; border-collapse: collapse; margin-top: 20px; font-size: 14px; }
                th { background-color: #047857; color: white; padding: 10px; border: 1px solid #065f46; }
                td { border: 1px solid #ccc; padding: 8px; }
                .total-row { background-color: #f0fdf4; font-weight: bold; }
                .footer { margin-top: 50px; display: flex; justify-content: flex-end; }
                .signature { border-top: 1px solid #000; padding-top: 5px; width: 200px; text-align: center; }
            </style>
        </head>
        <body>
            <div class="header">
                <h1>সোনালী লাইফ ইন্স্যুরেন্স</h1>
                <p>পেমেন্ট তালিকা | তারিখ: ${new Date().toLocaleDateString('bn-BD')}</p>
            </div>
            <table>
                <thead>
                    <tr>
                        <th>ক্রমিক</th><th>কোড</th><th>শাখা</th><th>নাম</th><th>মোবাইল</th><th>সিরিয়াল</th><th>টাকা</th>
                    </tr>
                </thead>
                <tbody>
                    ${tableRows}
                    <tr class="total-row">
                        <td colspan="6" style="text-align:right">সর্বমোট:</td>
                        <td style="text-align:right">${toBanglaDigits(totalAmount)}</td>
                    </tr>
                </tbody>
            </table>
            ${note ? `<div style="margin-top:20px; padding:15px; background:#f9f9f9; border:1px solid #eee;"><strong>নোট:</strong> ${note}</div>` : ''}
            <div class="footer">
                <div class="signature">কর্তৃপক্ষের স্বাক্ষর</div>
            </div>
            <script>window.print();</script>
        </body>
        </html>
    `;
    printWindow.document.write(htmlContent);
    printWindow.document.close();
  };

  const handleDownloadCSV = () => {
    let content = "\uFEFFক্রমিক,কোড,শাখা,নাম,মোবাইল,সিরিয়াল,টাকা\n";
    billItems.forEach((item, idx) => {
        content += `"${toBanglaDigits(idx+1)}","${toBanglaDigits(item.code)}","${item.branch}","${item.name}","${item.mobile}","${item.serial}","${toBanglaDigits(item.amount || 0)}"\n`;
    });
    content += `,,,,,,সর্বমোট: ${toBanglaDigits(totalAmount)}\n`;

    const blob = new Blob([content], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `sonali_list_${Date.now()}.csv`;
    link.click();
  };

  return (
    <div className="space-y-6">
      <div className="bg-white p-6 rounded-2xl shadow-lg border border-emerald-100">
        <div className="flex items-center gap-3 mb-6 border-b border-gray-100 pb-4">
          <span className="bg-orange-500 text-white w-8 h-8 flex items-center justify-center rounded-full font-bold">২</span>
          <h2 className="text-xl font-bold text-gray-800">বিল / তালিকা তৈরি (Custom List)</h2>
        </div>

        <div className="mb-4">
          <label className="block text-gray-700 font-medium mb-2">বাল্ক কোড ইনপুট (কমা দিয়ে আলাদা করুন)</label>
          <div className="relative">
            <textarea
                value={inputCodes}
                onChange={(e) => setInputCodes(e.target.value)}
                placeholder="যেমন: ৩৪১, ২৮৫, ১৮৫, ২৮৪"
                className="w-full h-24 p-4 border-2 border-gray-200 rounded-xl focus:border-orange-500 focus:ring-0 outline-none transition-all resize-none text-lg"
            />
            {inputCodes && (
                <button 
                    onClick={() => setInputCodes('')}
                    className="absolute top-3 right-3 text-gray-400 hover:text-red-500 bg-white p-1 rounded-full shadow-sm"
                >
                    <Eraser size={16} />
                </button>
            )}
          </div>
        </div>

        <div className="flex gap-3">
          <button
            onClick={handleGenerateList}
            disabled={loading || !inputCodes.trim()}
            className="bg-orange-500 hover:bg-orange-600 text-white px-6 py-3 rounded-xl font-bold shadow-md shadow-orange-100 transition-all active:scale-95 disabled:opacity-50 flex-1 flex items-center justify-center gap-2"
          >
            {loading ? 'প্রসেসিং...' : <><Plus size={20} /> যোগ করুন</>}
          </button>
          {billItems.length > 0 && (
             <button
                onClick={() => { 
                    if(window.confirm('আপনি কি নিশ্চিত যে সম্পূর্ণ লিস্ট মুছে ফেলতে চান?')) {
                        setBillItems([]); 
                    }
                }}
                className="bg-red-50 hover:bg-red-100 text-red-600 px-6 py-3 rounded-xl font-bold transition-all border border-red-200"
            >
                মুছুন
            </button>
          )}
        </div>

        {notFoundCodes.length > 0 && (
            <div className="mt-4 p-3 bg-red-50 text-red-600 rounded-lg flex items-start gap-2 text-sm border border-red-100 animate-in fade-in">
                <AlertCircle size={16} className="mt-1 flex-shrink-0" />
                <span>পাওয়া যায়নি: {notFoundCodes.join(', ')}</span>
            </div>
        )}
