export default AllBranchesModal;

import React, { useState, useRef, useEffect } from 'react';
import { Search, Copy, Check, PlusCircle, Clock, RotateCcw, X, MapPin, User, Phone, ChevronRight, List } from 'lucide-react';
import { BRANCH_DATABASE, toBanglaDigits, toEnglishDigits } from '../constants';
import { BranchData } from '../types';
import AllBranchesModal from './AllBranchesModal';

interface SearchSectionProps {
  onSearchComplete: () => void;
  onAddToBill: (code: string, data: BranchData) => void;
}

const SearchSection: React.FC<SearchSectionProps> = ({ onSearchComplete, onAddToBill }) => {
  const [query, setQuery] = useState('');
  const [suggestions, setSuggestions] = useState<{ code: string; data: BranchData }[]>([]);
  const [result, setResult] = useState<{ code: string; data: BranchData } | null>(null);
  const [loading, setLoading] = useState(false);
  const [copiedField, setCopiedField] = useState<string | null>(null);
  const [recentSearches, setRecentSearches] = useState<{ code: string; name: string }[]>([]);
  const [selectedIndex, setSelectedIndex] = useState(-1);
  const [showAllModal, setShowAllModal] = useState(false);

  const wrapperRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  // Load recent searches
  useEffect(() => {
    const saved = localStorage.getItem('sonali_recent_searches');
    if (saved) {
      setRecentSearches(JSON.parse(saved));
    }
  }, []);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (wrapperRef.current && !wrapperRef.current.contains(event.target as Node)) {
        setSuggestions([]);
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, [wrapperRef]);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const val = e.target.value;
    setQuery(val);
    setSelectedIndex(-1);

    if (val.length < 1) {
      setSuggestions([]);
      return;
    }

    const searchTerm = toEnglishDigits(val.toLowerCase());
    const matches: { code: string; data: BranchData }[] = [];

    Object.keys(BRANCH_DATABASE).forEach((code) => {
      const data = BRANCH_DATABASE[code];
      const searchText = (code + data.branch + data.name + data.mobile).toLowerCase();
      if (searchText.includes(searchTerm)) {
        matches.push({ code, data });
      }
    });
    setSuggestions(matches.slice(0, 8));
  };

  const handleKeyDown = (e: React.KeyboardEvent<HTMLInputElement>) => {
    if (suggestions.length === 0) return;

    if (e.key === 'ArrowDown') {
      e.preventDefault();
      setSelectedIndex((prev) => (prev < suggestions.length - 1 ? prev + 1 : 0));
    } else if (e.key === 'ArrowUp') {
      e.preventDefault();
      setSelectedIndex((prev) => (prev > 0 ? prev - 1 : suggestions.length - 1));
    } else if (e.key === 'Enter') {
      e.preventDefault();
      if (selectedIndex >= 0 && suggestions[selectedIndex]) {
        const item = suggestions[selectedIndex];
        setQuery(item.code);
        executeSearch(item.code);
      } else {
        executeSearch();
      }
    } else if (e.key === 'Escape') {
      setSuggestions([]);
    }
  };

  const addToRecent = (code: string, name: string) => {
    const newRecent = [{ code, name }, ...recentSearches.filter(r => r.code !== code)].slice(0, 6);
    setRecentSearches(newRecent);
    localStorage.setItem('sonali_recent_searches', JSON.stringify(newRecent));
  };

  const executeSearch = (searchCode?: string) => {
    const codeToSearch = searchCode || toEnglishDigits(query);
    if (!codeToSearch) return;

    setLoading(true);
    setSuggestions([]);

    setTimeout(() => {
      const data = BRANCH_DATABASE[codeToSearch];
      if (data) {
        setResult({ code: codeToSearch, data });
        addToRecent(codeToSearch, data.branch);
        onSearchComplete();
      } else {
        setResult(null);
        alert('কোনো তথ্য পাওয়া যায়নি');
      }
      setLoading(false);
    }, 300);
  };

  const clearSearch = () => {
    setQuery('');
    setSuggestions([]);
    setResult(null);
    inputRef.current?.focus();
  };

  const copyToClipboard = (text: string, field: string) => {
    navigator.clipboard.writeText(text);
    setCopiedField(field);
    setTimeout(() => setCopiedField(null), 2000);
  };

  // Helper to highlight matching text
  const HighlightedText = ({ text, highlight }: { text: string, highlight: string }) => {
    if (!highlight.trim()) return <span>{text}</span>;
    const parts = text.split(new RegExp(`(${highlight})`, 'gi'));
    return (
      <span>
        {parts.map((part, i) => 
          part.toLowerCase() === highlight.toLowerCase() ? 
            <span key={i} className="bg-yellow-200 text-black font-semibold rounded-[2px] px-[1px]">{part}</span> : 
            part
        )}
      </span>
    );
  };

  return (
    <>
    <div className="bg-white p-6 rounded-2xl shadow-lg border border-emerald-100 mb-6 transition-all duration-300 hover:shadow-xl relative">
      <div className="flex items-center justify-between gap-3 mb-6 border-b border-gray-100 pb-4">
        <div className="flex items-center gap-3">
            <span className="bg-emerald-600 text-white w-8 h-8 flex items-center justify-center rounded-full font-bold">১</span>
            <h2 className="text-xl font-bold text-gray-800">দ্রুত অনুসন্ধান (Smart Search)</h2>
        </div>
        <button 
            onClick={() => setShowAllModal(true)}
            className="flex items-center gap-2 text-emerald-600 hover:bg-emerald-50 px-3 py-1.5 rounded-lg text-sm font-bold transition-all border border-emerald-200 hover:border-emerald-300 active:scale-95"
        >
            <List size={16} />
            <span className="hidden sm:inline">সকল ব্রাঞ্চ দেখুন</span>
            <span className="sm:hidden">সকল</span>
        </button>
      </div>

      <div className="relative mb-6" ref={wrapperRef}>
        <div className="flex gap-2">
          <div className="relative flex-1 group">
            <input
              ref={inputRef}
              type="text"
              value={query}
              onChange={handleInputChange}
              onKeyDown={handleKeyDown}
              placeholder="কোড, শাখার নাম বা কর্মকর্তার নাম..."
              className="w-full p-4 pl-12 pr-10 border-2 border-gray-200 rounded-xl focus:border-emerald-500 focus:ring-4 focus:ring-emerald-50 outline-none transition-all text-lg font-medium text-gray-700 placeholder-gray-400 group-hover:border-emerald-300"
              autoComplete="off"
            />
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 group-focus-within:text-emerald-500 transition-colors" />

            {query && (
              <button 
                onClick={clearSearch}
                className="absolute right-3 top-1/2 -translate-y-1/2 p-1 text-gray-400 hover:text-red-500 hover:bg-red-50 rounded-full transition-all"
                title="মুছুন"
              >
                <X size={18} />
              </button>
            )}
          </div>
          <button
            onClick={() => executeSearch()}
            disabled={loading}
            className="bg-emerald-600 hover:bg-emerald-700 text-white px-6 md:px-8 rounded-xl font-bold shadow-md shadow-emerald-200 transition-all active:scale-95 disabled:opacity-50 disabled:active:scale-100 flex items-center justify-center min-w-[100px]"
          >
            {loading ? (
              <div className="w-5 h-5 border-2 border-white border-t-transparent rounded-full animate-spin"></div>
            ) : (
              'খুঁজুন'
            )}
          </button>
        </div>

        {/* Suggestions Dropdown */}
        {query.length > 0 && !result && (
          <div className="absolute top-full left-0 right-0 bg-white border border-gray-100 rounded-xl mt-2 shadow-2xl z-50 max-h-80 overflow-y-auto overflow-x-hidden animate-in slide-in-from-top-2 duration-200 scroll-smooth">
            {suggestions.length > 0 ? (
              suggestions.map((item, index) => (
                <div
                  key={item.code}
                  onClick={() => {
                    setQuery(item.code);
                    executeSearch(item.code);
                  }}
                  className={`p-3 cursor-pointer border-b border-gray-50 last:border-0 flex justify-between items-center transition-colors ${
                    index === selectedIndex ? 'bg-emerald-50 border-l-4 border-l-emerald-500 pl-2' : 'hover:bg-gray-50 border-l-4 border-l-transparent'
                  }`}
                >
                  <div className="flex items-center gap-3 overflow-hidden">
                    <div className="w-10 h-10 bg-gray-100 rounded-full flex items-center justify-center text-emerald-700 font-bold text-sm shrink-0">
                      {toBanglaDigits(item.code)}
                    </div>
                    <div className="min-w-0">
                      <p className="font-semibold text-gray-800 truncate">
                        <HighlightedText text={item.data.branch} highlight={toBanglaDigits(query)} />
                        {/* Try matching english query too if visual highlight is needed, but mostly bangla display */}
                      </p>
                      <p className="text-gray-500 text-xs truncate flex items-center gap-1">
                        <User size={10} /> <HighlightedText text={item.data.name} highlight={query} />
                      </p>
                    </div>
                  </div>
                  <ChevronRight size={16} className="text-gray-300 shrink-0" />
                </div>
              ))
            ) : (
              <div className="p-8 text-center text-gray-400">
                <div className="bg-gray-50 w-12 h-12 rounded-full flex items-center justify-center mx-auto mb-2">
                  <Search size={20} />
                </div>
                <p>কোনো ফলাফল পাওয়া যায়নি</p>
              </div>
            )}
          </div>
        )}
      </div>

      {/* Recent Searches */}
      {!result && recentSearches.length > 0 && query.length === 0 && (
        <div className="mb-4 animate-in fade-in duration-500">
            <p className="text-xs text-gray-400 font-bold uppercase mb-2 flex items-center gap-1">
                <Clock size={12} /> সাম্প্রতিক অনুসন্ধান
            </p>
            <div className="flex flex-wrap gap-2">
                {recentSearches.map((item) => (
                    <button
                        key={item.code}
                        onClick={() => { setQuery(item.code); executeSearch(item.code); }}
                        className="group text-xs bg-gray-50 hover:bg-emerald-50 text-gray-600 hover:text-emerald-700 px-3 py-1.5 rounded-full transition-all border border-gray-200 hover:border-emerald-200 flex items-center gap-1"
                    >
                        <span className="font-bold">{toBanglaDigits(item.code)}</span>
                        <span className="group-hover:opacity-100 opacity-70 transition-opacity">- {item.name}</span>
                    </button>
                ))}
            </div>
        </div>
      )}

      {/* Search Result Card */}
      {result && (
        <div className="bg-gradient-to-br from-emerald-50 via-white to-emerald-50/50 border border-emerald-100 rounded-xl p-6 animate-in zoom-in-95 duration-300 relative overflow-hidden shadow-sm">
          {/* Background pattern */}
          <div className="absolute top-0 right-0 opacity-5 -translate-y-1/4 translate-x-1/4 pointer-events-none">
             <Search size={200} />
          </div>

          <div className="flex justify-between items-start relative z-10 mb-4">
             <div>
                <span className="bg-emerald-100 text-emerald-800 text-xs px-2 py-1 rounded-full font-bold">ব্রাঞ্চ কোড: {toBanglaDigits(result.code)}</span>
                <h3 className="text-2xl font-bold text-gray-800 mt-2">{result.data.branch}</h3>
                <p className="text-gray-500 text-sm flex items-center gap-1 mt-1">
                    <User size={14} /> {result.data.name}
                </p>
             </div>
             <button 
                onClick={() => { setResult(null); setQuery(''); inputRef.current?.focus(); }}
                className="text-gray-400 hover:text-red-500 p-2 hover:bg-red-50 rounded-full transition-all"
                title="বন্ধ করুন"
             >
                <RotateCcw size={20} />
             </button>
          </div>

          <div className="grid gap-3 relative z-10 bg-white/60 p-4 rounded-xl backdrop-blur-sm border border-white/50">
             {[
               { label: 'মোবাইল', value: result.data.mobile, key: 'mobile', icon: <Phone size={14} /> },
               { label: 'এক্সটেনশন', value: result.data.ext, key: 'ext', icon: <span className="text-[10px] font-bold">EXT</span> },
               { label: 'ইমেইল', value: result.data.email, key: 'email', icon: <span className="text-[10px] font-bold">@</span> },
             ].map((row) => (
               <div key={row.key} className="flex items-center justify-between border-b border-gray-100 last:border-0 pb-2 mb-1 last:mb-0 last:pb-0">
                 <span className="text-sm font-medium text-gray-500 flex items-center gap-2">
                    <span className="w-6 h-6 rounded-full bg-emerald-50 text-emerald-600 flex items-center justify-center">
                        {row.icon}
                    </span>
                    {row.label}
                 </span>
                 <div className="flex items-center gap-2">
                    <span className="text-gray-800 font-semibold text-right">{row.value}</span>
                    <button 
                    onClick={() => copyToClipboard(row.value, row.key)}
                    className="p-1.5 hover:bg-emerald-100 rounded-md text-emerald-600 transition-colors opacity-70 hover:opacity-100"
                    title="কপি করুন"
                    >
                    {copiedField === row.key ? <Check size={14} /> : <Copy size={14} />}
                    </button>
                 </div>
               </div>
             ))}
          </div>

          <div className="mt-6 pt-4 border-t border-emerald-100 relative z-10">
             <button
               onClick={() => onAddToBill(result.code, result.data)}
               className="w-full bg-emerald-600 hover:bg-emerald-700 text-white py-3.5 rounded-xl font-bold flex items-center justify-center gap-2 shadow-lg shadow-emerald-200/50 hover:shadow-emerald-300/50 active:scale-[0.98] transition-all"
             >
                <PlusCircle size={20} />
                লিস্টে যোগ করুন
             </button>
          </div>
        </div>
      )}
    </div>

    <AllBranchesModal 
        isOpen={showAllModal} 
        onClose={() => setShowAllModal(false)} 
        onAddToBill={(code, data) => {
            onAddToBill(code, data);
            // Optional: close modal on add?
            // setShowAllModal(false); 
        }}
    />
    </>
  );
};

